-- 刘宇轩 Week6 PostgreSQL 导入
-- 运行此文件即可建表+导入全部数据

DROP TABLE IF EXISTS lyx_subscription_flow;
CREATE TABLE lyx_subscription_flow (id SERIAL PRIMARY KEY, company_code VARCHAR(10), company_name VARCHAR(50), pdf_page INTEGER, subscription_date VARCHAR(20), subscriber VARCHAR(100), shares_wan NUMERIC(15,4), amount_wan NUMERIC(15,2), price_yuan NUMERIC(15,4), capital_wan NUMERIC(15,4), evidence TEXT, source VARCHAR(50), review_status VARCHAR(20), investor_type VARCHAR(50), is_pevc VARCHAR(10));

DROP TABLE IF EXISTS lyx_equity_snapshot;
CREATE TABLE lyx_equity_snapshot (id SERIAL PRIMARY KEY, company_code VARCHAR(10), company_name VARCHAR(50), pdf_page INTEGER, time_point VARCHAR(200), equity_scope VARCHAR(200), total_shares_wan NUMERIC(15,4), total_capital_wan NUMERIC(15,4), shareholder_name VARCHAR(100), shares_wan NUMERIC(15,4), capital_wan NUMERIC(15,4), share_ratio NUMERIC(10,4), evidence TEXT, source VARCHAR(50), review_status VARCHAR(20));

DROP TABLE IF EXISTS lyx_share_transfer_flow;
CREATE TABLE lyx_share_transfer_flow (id SERIAL PRIMARY KEY, company_code VARCHAR(10), company_name VARCHAR(50), pdf_page INTEGER, transfer_date VARCHAR(20), transferor VARCHAR(100), transferee VARCHAR(100), shares_wan NUMERIC(15,4), amount_wan NUMERIC(15,2), price_yuan NUMERIC(15,4), evidence TEXT, source VARCHAR(50), review_status VARCHAR(20));

