INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('603418','友升股份',48,'2003-07-03','第一美亚基金','陈桂荣',NULL,NULL,NULL,'2003年7月3日，第一美亚基金与陈桂荣签署了《股权转让协议》，约定第一美亚基金以6.0753万美元的价格向陈桂荣转让其所持有第一美亚100%的股权，陈桂荣间接取得友升有限55%股权。',NULL,'unchecked');
INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('603418','友升股份',48,'2003-07-30','第一美亚','美国日升',NULL,NULL,NULL,'2003年7月30日，第一美亚与美国日升签署《股权转让协议》，约定第一美亚将其持有的友升有限55%股权转让给美国日升，第一美亚不再持有友升有限股权，该次转让系由罗世兵同一控制下的两家企业进行的转让，未支付对价。',NULL,'unchecked');
INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('603418','友升股份',49,'2007-08','占庆华','罗世兵',NULL,NULL,NULL,'2007年8月，占庆华已将其持有美国日升100%股权转让予罗世兵，解除上述代持关系。',NULL,'unchecked');
INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('603418','友升股份',50,'2020-07-02','李雷','付忠祥',NULL,NULL,NULL,'2020年7月2日，李雷因个人职业发展规划原因从公司离职。经李雷与付忠祥协商一致，李雷将共青城泽升5万元的出资份额以原价转让予付忠祥，并收到出资款返还97,625.00元，付忠祥与李雷之间的股权代持关系解除。',NULL,'unchecked');
INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('603418','友升股份',50,'2021-05-31','万海亮','付忠祥',NULL,NULL,NULL,'2021年5月31日，万海亮因个人职业发展规划原因从公司离职。经万海亮与付忠祥协商一致，万海亮将共青城泽升5万元的出资份额以原价转让予付忠祥，并收到出资款返还97,625.00元，付忠祥与万海亮之间的股权代持关系解除。',NULL,'unchecked');
