INSERT INTO lyx_share_transfer_flow (company_code,company_name,pdf_page,transfer_date,transferor,transferee,shares_wan,amount_wan,price_yuan,evidence,source,review_status) VALUES ('688775','影石创新',65,'2023-03-24','德朴投资','汇智同裕',287,NULL,5,'2023年1月28日和2023年2月17日，影石创新分别召开董事会和股东大会并形成决议，同意德朴投资以1,462.7126万元的对价向汇智同裕转让股本287.0651万元，并据此修订公司章程。上述股权变动系原股东之间的股权转让行为，不属于最近一年新增股东的情形；本次股权转让未造成发行人实际控制人的变更，未对发行人的股权结构的稳定性和持续盈利能力造成不利影响。',NULL,'unchecked');
INSERT INTO lyx_subscription_flow (company_code,company_name,pdf_page,subscription_date,subscriber,shares_wan,amount_wan,price_yuan,capital_wan,evidence,source,review_status,investor_type,is_pevc) VALUES ('920100','三协电机',53,'2022-07-09','稳正景明',265,1187,4,NULL,'2022 年 7 月 9 日，常州三协电机股份有限公司 2022 年度第一次临时股东大会审议通过《关于<常州三协电机股份有限公司股票定向发行说明书>的议案》，公司向稳正景明和长泽创投定向发行股票，发行股数为530万股，每股认购价格为 4.48元/股。本次募集资金总额为2,374.40万元，以货币资金形式认缴，其中530.00 万元计入注册资本，1,844.40 万元增加资本公积。','auto','unchecked',NULL,NULL);
INSERT INTO lyx_subscription_flow (company_code,company_name,pdf_page,subscription_date,subscriber,shares_wan,amount_wan,price_yuan,capital_wan,evidence,source,review_status,investor_type,is_pevc) VALUES ('920100','三协电机',53,'2022-07-09','长泽创投',265,1187,4,NULL,'2022 年 7 月 9 日，常州三协电机股份有限公司 2022 年度第一次临时股东大会审议通过《关于<常州三协电机股份有限公司股票定向发行说明书>的议案》，公司向稳正景明和长泽创投定向发行股票，发行股数为530万股，每股认购价格为 4.48元/股。本次募集资金总额为2,374.40万元，以货币资金形式认缴，其中530.00 万元计入注册资本，1,844.40 万元增加资本公积。','auto','unchecked',NULL,NULL);
INSERT INTO lyx_subscription_flow (company_code,company_name,pdf_page,subscription_date,subscriber,shares_wan,amount_wan,price_yuan,capital_wan,evidence,source,review_status,investor_type,is_pevc) VALUES ('920100','三协电机',53,'2023-08-28','（未披露具体认购方名称）',318,1723,5,NULL,'2023年 8月 28日，公司实际发行 318.5 万股，增发价格为 5.41 元/股，全部以货币资金形式认缴，实际募集资金总额为 1,723.09万元，其中318.5万元计入股本，1,404.59万元计入资本公积，本次发行完成后公司股本总额增至3,848.50万元，由苏亚金诚审验，于 2023年 9月 8 日出具苏亚验[2023]10号验资报告。','auto','unchecked',NULL,NULL);
